using System.Collections.Generic;
using UnityEngine;

public class CorridorLoop : MonoBehaviour
{
    [Header("References")]
    [SerializeField] private Transform reference;           // Main Camera
    [SerializeField] private List<Transform> segments;      // Corridor_01, Corridor_02, ...

    [Header("Motion")]
    [SerializeField] private float speed = 6f;

    [Header("Recycle")]
    [Tooltip("Segment tamamen kameran�n arkas�na ge�ince recycle olsun.")]
    [SerializeField] private float recycleBehind = 5f;

    private void Reset()
    {
        if (reference == null && Camera.main != null)
            reference = Camera.main.transform;
    }

    private void Start()
    {
        if (reference == null && Camera.main != null)
            reference = Camera.main .transform;

        // Ba�lang��ta segmentleri ger�ek u�lar�na g�re arka arkaya diz
        AlignSegmentsByBounds();
    }

    private void Update()
    {
        if (segments == null || segments.Count == 0) return;

        // 1) Hepsini geriye kayd�r
        float dz = speed * Time.deltaTime;
        for (int i = 0; i < segments.Count; i++)
        {
            if (segments[i] == null) continue;
            segments[i].position += Vector3.back * dz;
        }

        if (reference == null) return;

        // 2) Kamera arkas�na tamamen d��en segmentleri en �ne yap��t�r
        float thresholdZ = reference.position.z - recycleBehind;

        for (int i = 0; i < segments.Count; i++)
        {
            Transform seg = segments[i];
            if (seg == null) continue;

            Bounds b = GetWorldBounds(seg);

            // Segmentin en �n ucu bile threshold'un arkas�na ge�tiyse tamamen arkada demektir
            if (b.max.z < thresholdZ)
            {
                float frontMostMaxZ = FindFrontMostMaxZ();

                // Bu segmentin current bounds.min.z ile pivot aras�ndaki offset'i koruyarak ta��
                float pivotToMin = seg.position.z - b.min.z;

                Vector3 p = seg.position;
                p.z = frontMostMaxZ + pivotToMin;   // minZ => frontMostMaxZ olacak �ekilde
                seg.position = p;
            }
        }
    }

    private void AlignSegmentsByBounds()
    {
        // segments listesindeki s�raya g�re diziyoruz: 0 en arkada, sonra 1,2...
        // �stersen 0'� ba�lang�� segmentin olarak sahnede istedi�in yere koy, di�erleri ona yap��s�n.

        if (segments == null || segments.Count == 0) return;

        // �lk segmenti referans al
        Transform first = segments[0];
        if (first == null) return;

        Bounds firstB = GetWorldBounds(first);
        float currentFrontMaxZ = firstB.max.z;

        for (int i = 1; i < segments.Count; i++)
        {
            Transform seg = segments[i];
            if (seg == null) continue;

            Bounds b = GetWorldBounds(seg);
            float pivotToMin = seg.position.z - b.min.z;

            Vector3 p = seg.position;
            // Bu segmentin minZ'sini bir �ncekinin maxZ'sine yap��t�r
            p.z = currentFrontMaxZ + pivotToMin;
            seg.position = p;

            // Yeni front max g�ncelle
            Bounds newB = GetWorldBounds(seg);
            currentFrontMaxZ = newB.max.z;
        }
    }

    private float FindFrontMostMaxZ()
    {
        float maxZ = float.NegativeInfinity;
        for (int i = 0; i < segments.Count; i++)
        {
            if (segments[i] == null) continue;
            Bounds b = GetWorldBounds(segments[i]);
            if (b.max.z > maxZ) maxZ = b.max.z;
        }
        return maxZ;
    }

    private Bounds GetWorldBounds(Transform root)
    {
        // Root alt�ndaki T�M rendererlardan birle�ik bounds ��kar�r (as�l fix burada)
        Renderer[] rs = root.GetComponentsInChildren<Renderer>();
        if (rs == null || rs.Length == 0)
        {
            // Renderer yoksa fallback: k���k bir bounds
            return new Bounds(root.position, Vector3.one);
        }

        Bounds b = rs[0].bounds;
        for (int i = 1; i < rs.Length; i++)
            b.Encapsulate(rs[i].bounds);

        return b;
    }
}

